define i1 @sext_square_bit14(i8 noundef %x) {
  %sx = sext i8 %x to i32
  %mul = mul nsw i32 %sx, %sx
  %and = and i32 %mul, 16384
  %cmp = icmp ne i32 %and, 0
  ret i1 %cmp
}

```

